var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이제...","JPN":"これで……","ENG":"And now...","TWN":"現在……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...둘 남았네요.","JPN":"……残り二人ですね。","ENG":"...Only two remain.","TWN":"……只剩兩個人了。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이전과는 확실히 다르군요. 정말 강해요.","JPN":"以前とは確実に違いますね。本当に強い。","ENG":"This is definitely different from before. You really are strong.","TWN":"確實和之前不同了，真的很強。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금의 저희로선 공격은커녕 살아남는 것도 벅차군요.","JPN":"今の僕たちでは、攻撃どころか生き延びるだけで精一杯です。","ENG":"At this rate, we can barely even survive, let alone attack.","TWN":"以現在的我們，別說反擊，連活下來都很吃力。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...알고 있다면, 왜 포기하지 않는 거죠?","JPN":"……分かっているなら、なぜ諦めないのですか？","ENG":"...If you know that, then why don't you give up?","TWN":"……既然知道，為什麼還不放棄？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"쓰러져간 동료들을 위해서라도, 우릴 기다리는 남은 분들을 위해서라도...","JPN":"倒れていった仲間たちのためにも、僕たちを待っている方々のためにも……","ENG":"For the sake of the comrades who've fallen... and for the ones still waiting for us...","TWN":"為了倒下的同伴，還有為了等待我們的人……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"쉽게 포기할 수는 없거든요.","JPN":"そう簡単に諦めるわけにはいきませんので。","ENG":"we can't give up so easily.","TWN":"我們不能輕易放棄。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...라는 건 표면적인 명분이고-","JPN":"……というのは、表向きの口実で。","ENG":"...That's the surface-level reason...","TWN":"……只是表面的理由。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"핵심은 시간을 버는 겁니다.","JPN":"実は時間稼ぎなんです。","ENG":"The real goal is to buy time.","TWN":"真正的目的是拖延時間。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그랬었죠. 당신도 남아있었네요.","JPN":"そうでした、あなたも残っていましたね。","ENG":"That's right. You were still here as well.","TWN":"原來如此。你也還在啊。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"발키리.","JPN":"ヴァルキリー。","ENG":"Valkyrie.","TWN":"女武神。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"...미안하군. 해묵은 일을 청산하느라 좀 늦었다.","JPN":"……遅れてすまない。古い因縁を片付けるのに手間取った。","ENG":"...My apologies. I was delayed settling an old matter.","TWN":"……抱歉，清算舊帳花了點時間。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"결국, 아스모데우스는 당신의 힘에 미치지 못했군요.","JPN":"結局アスモデウスはあなたに及ばなかったのですね。","ENG":"In the end, Asmodeus couldn't match your strength.","TWN":"結果，阿斯蒙蒂斯還是不及你的力量啊。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 처음 왔을 때보다 힘이 약해진 걸 보니, 제법 분전한 모양이네요.","JPN":"でも最初ここに来た時より力が弱まっているのは、かなり激しく戦ったということでしょう。","ENG":"But judging by how weakened you are compared to when you first arrived, it seems you put up quite a fight.","TWN":"不過看來你比剛來時虛弱了不少，看來也拼盡全力了啊。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"...유미나. 혼자 일어설 수 있겠나?","JPN":"……ヤナギ・ミナ、一人で立てるか？","ENG":"...Yoo Mina. Can you stand on your own?","TWN":"……劉米娜，你還站得起來嗎？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그야... 물론이지.","JPN":"それは……もちろん。","ENG":"Of course... I can.","TWN":"那是……當然囉。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그렇다면 온 힘을 쥐어짜서라도 울브즈베인을 녀석의 심장에 박아넣어라.","JPN":"なら、力を振り絞ってでもウルブズベインをやつの心臓にぶち込め。","ENG":"Then force out every last bit of strength you have and drive Wolvesbane into the heart.","TWN":"那就使出全身的力量，把狼之災禍刺進那傢伙的心臟。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"내가 도와줄 수 있는 건, 녀석에게서 틈을 만드는 것까지니까.","JPN":"私にできるのは、やつの隙を作ることだけだ。","ENG":"All I can do is create an opening for you.","TWN":"我能幫的，就只有為你製造破綻。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...그 정도면 충분해!","JPN":"……それで十分！","ENG":"...That's more than enough!","TWN":"……那就夠了！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"사라졌...?","JPN":"消え……？","ENG":"She disappeared...?","TWN":"消失了……？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...큭!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……呃！"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"반응이 좋군.","JPN":"いい反応だな。","ENG":"Nice reaction.","TWN":"反應不錯。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"하지만 아스모데우스였다면 막는 데서 그치지 않고 반격까지 했을 거다.","JPN":"だが、アスモデウスなら防ぐだけじゃなく反撃までしたはずだ。","ENG":"But if it had been Asmodeus, she wouldn't have stopped at blocking. She would have counterattacked as well.","TWN":"但如果是阿斯蒙蒂斯，不只會擋下來，還會反擊。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"넌, 그 녀석에 비하면 소질이 한참 부족해!","JPN":"お前はあいつに比べれば遥かに劣る！","ENG":"Compared to her, you're severely lacking in aptitude!","TWN":"你比起她，資質還差得遠了！"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...가르치려 들기는!","JPN":"……偉そうに！","ENG":"...Don't presume to lecture me!","TWN":"……少說教了！"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};